#include<cstdio>
#include<iostream>
#include<algorithm>
using namespace std;

int W, n, w[100005], v[100005], dp[40004];
int cnt;

int main(){
	cin >> n >> W;
	for(int i = 1; i <= n; i++)
	{
		int vi, wi, m;
		cin >> vi >> wi >> m;
		int p = 1;
		while(p < m)
		{
			m -= p;
			v[++cnt] = vi * p;
			w[cnt] = wi * p;
			p *= 2;
		}
		v[++cnt] = vi * m;
		w[cnt] = wi * m;
	}
	for(int i = 1; i <= cnt; i++)
		for(int j = W; j >= w[i]; j--)
			dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
	cout << dp[W];
	return 0;
}
